from flask import Flask, request
from elasticsearch import Elasticsearch

app = Flask(__name__)
es = Elasticsearch([{'host': 'localhost', 'port': 9200}]) # Connect to your local instance of Elasticsearch

@app.route('/execute_script', methods=['POST'])
def execute_script():
    req = request.get_json()
    
    if 'script' not in req:
        return {"error": "No script provided"}, 400
    
    script = req['script']
    
    # The inline property must be set to true in the cluster configuration to enable inline scripts.
    body = {
        "size": 0,
        "aggs": {
            "custom_agg": {
                "scripted": {
                    "init_scripts" : [{ "inline": """{}""".format(script)}],
                    "map_scripts": [],
                    "combine_scripts": [],
                    "reduce_scripts": []
                }
            }
        }
    }
    
    res = es.search(index='your-index', body=body) # replace 'your-index' with your index name
    
    if '_agg_1' in res['aggregations']: 
        return {"result": res['aggregations']['custom_agg']['value']}, 200
    else:
        return {"error": "Script execution failed"}, 500
        
if __name__ == '__main__':
    app.run(host='localhost', port=8080) # Run on localhost at port 8080, you can adjust this to your needs